import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { COLORS } from '../styles/theme';

export default function LogoBanner({ compact = false }) {
  return (
    <View style={[styles.wrap, compact && styles.compactWrap]}>
      <View style={styles.badge}>
        <Text style={styles.badgeText}>🐶</Text>
      </View>
      <View>
        <Text style={styles.brand}>Sano y Salvo</Text>
        <Text style={styles.tag}>Red de búsqueda y rescate de mascotas</Text>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  wrap: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 12,
    padding: 12,
    backgroundColor: COLORS.surface,
    borderRadius: 18,
    borderWidth: 1,
    borderColor: COLORS.border
  },
  compactWrap: { paddingVertical: 8 },
  badge: {
    width: 48,
    height: 48,
    borderRadius: 16,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: COLORS.soft
  },
  badgeText: { fontSize: 24 },
  brand: { fontSize: 18, fontWeight: '800', color: COLORS.text },
  tag: { fontSize: 12, color: COLORS.muted, marginTop: 2 }
});
